diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..a21e39cba188 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -9426,12 +9426,46 @@ isImpliedCondICmps(CmpPredicate LPred, const Value *L0, const Value *L1,
       match(L0, m_c_Add(m_Specific(L1), m_Specific(R1))))
     return CmpPredicate::getMatching(LPred, RPred).has_value();

+  // (sub(ptrtoint(X), ptrtoint(Y))) == NZ  implies  X != Y  if NZ != 0
+  // (sub(ptrtoint(X), ptrtoint(Y))) != 0   implies  X != Y
+  // Also handle the canonicalized form with trunc(ptrtoint(...)).
+  Value *X, *Y;
+  auto PtrToIntOrTruncPtrToInt = [](Value *&V) {
+    return m_CombineOr(m_PtrToInt(m_Value(V)),
+                       m_Trunc(m_PtrToInt(m_Value(V))));
+  };
+  if ((match(L0, m_Sub(PtrToIntOrTruncPtrToInt(X),
+                       PtrToIntOrTruncPtrToInt(Y))) ||
+       match(L0, m_Sub(PtrToIntOrTruncPtrToInt(Y),
+                       PtrToIntOrTruncPtrToInt(X)))) &&
+      ((X == R0 && Y == R1) || (X == R1 && Y == R0))) {
+    if (LPred == CmpInst::ICMP_EQ || LPred == CmpInst::ICMP_NE) {
+      ConstantRange L1CR = computeConstantRange(
+          L1, ICmpInst::isSigned(LPred), /* UseInstrInfo=*/true,
+          /*AC=*/nullptr, /*CxtI=*/nullptr, /*DT=*/nullptr,
+          MaxAnalysisRecursionDepth - 1);
+      bool LPredSaysNonZero =
+          (LPred == CmpInst::ICMP_EQ &&
+           !L1CR.contains(APInt::getZero(L1CR.getBitWidth()))) ||
+          (LPred == CmpInst::ICMP_NE &&
+           L1CR.isSingleElement() &&
+           L1CR.getSingleElement()->isZero());
+      if (LPredSaysNonZero) {
+        if (ICmpInst::isEquality(RPred))
+          return RPred == CmpInst::ICMP_NE;
+      }
+    }
+  }
+
   if (auto P = CmpPredicate::getMatching(LPred, RPred))
     return isImpliedCondOperands(*P, L0, L1, R0, R1);

+
   return std::nullopt;
 }

+/// Return true if LHS implies RHS is true.  Return false if LHS implies RHS is
+
 /// Return true if LHS implies RHS is true.  Return false if LHS implies RHS is
 /// false.  Otherwise, return std::nullopt if we can't infer anything.  We
 /// expect the RHS to be an icmp and the LHS to be an 'and', 'or', or a 'select'
@@ -10122,6 +10156,22 @@ addValueAffectedByCondition(Value *V,
       if (isa<Instruction>(Op) || isa<Argument>(Op))
         InsertAffected(Op);
     }
+
+    // Peek through sub(ptrtoint(X), ptrtoint(Y)) to find X and Y. This allows
+    // us to prove X != Y from assumes like (ptrtoint(X) - ptrtoint(Y)) != 0.
+    // Also handle the case where ptrtoint is canonicalized to ptrtoint+trunc.
+    Value *X, *Y;
+    auto PtrToIntOrTruncPtrToInt = [](Value *&V) {
+      return m_CombineOr(m_PtrToInt(m_Value(V)),
+                         m_Trunc(m_PtrToInt(m_Value(V))));
+    };
+    if (match(I, m_Sub(PtrToIntOrTruncPtrToInt(X),
+                       PtrToIntOrTruncPtrToInt(Y)))) {
+      if (isa<Instruction>(X) || isa<Argument>(X))
+        InsertAffected(X);
+      if (isa<Instruction>(Y) || isa<Argument>(Y))
+        InsertAffected(Y);
+    }
   }
 }

